// RP2040 Internal Temp + PWM Lab
// Board-specific focus beyond classic AVR:
// - RP2040 internal temperature sensor via ADC channel 4 (when pico-sdk headers available)
// - 12-bit analog path + high-resolution PWM scaling on Pico

#if !defined(ARDUINO_ARCH_RP2040)
#error This sketch targets RP2040 only (wokwi-pi-pico).
#endif

#include <Arduino.h>

#if __has_include("hardware/adc.h")
  #include "hardware/adc.h"
  #define HAS_RP2040_HW_ADC 1
#else
  #define HAS_RP2040_HW_ADC 0
#endif

const int LED_PIN = 15;
const int POT_PIN = 26;

float readInternalTempC() {
#if HAS_RP2040_HW_ADC
  adc_select_input(4);
  uint16_t raw = adc_read();
  const float conversion = 3.3f / 4096.0f;
  float voltage = raw * conversion;
  // RP2040 datasheet conversion:
  // T = 27 - (Vtemp - 0.706)/0.001721
  return 27.0f - (voltage - 0.706f) / 0.001721f;
#else
  // Fallback if low-level headers are unavailable in this core build
  return NAN;
#endif
}

void setup() {
  Serial.begin(115200);
  delay(200);
  Serial.println("RP2040 Internal Temp + PWM Lab");

  pinMode(LED_PIN, OUTPUT);
  analogReadResolution(12);

#if HAS_RP2040_HW_ADC
  adc_init();
  adc_set_temp_sensor_enabled(true);
#endif
}

void loop() {
  int pot = analogRead(POT_PIN); // 0..4095 on RP2040 cores with 12-bit read
  int pwm = map(pot, 0, 4095, 0, 255);
  pwm = constrain(pwm, 0, 255);
  analogWrite(LED_PIN, pwm);

  float t = readInternalTempC();
  Serial.print("pot=");
  Serial.print(pot);
  Serial.print(" pwm=");
  Serial.print(pwm);
  Serial.print(" tempC=");
  if (isnan(t)) {
    Serial.println("n/a");
  } else {
    Serial.println(t, 2);
  }

  delay(150);
}
